// 纯 JS 多维过滤/聚合引擎,无 DOM/shadow/uplink 足迹。三载体一致。把结果接目录已有图库渲染。
import crossfilter from 'https://cdn.jsdelivr.net/npm/crossfilter2@1.5.4/+esm';
const cf = crossfilter(data.records);
const dim = cf.dimension(d => d[data.dimensionKey]);
if (data.range) dim.filterRange(data.range);
const grp = dim.group();          // 按维度分箱计数
const bins = grp.all();           // [{key, value}] → 喂柱状/直方
const rows = dim.top(Infinity);   // 当前过滤后的行 → 喂散点/表
